// 2D floor-plan pan helper (hand-drag to move the zoomed stage).
// Bed positions are generated by the layout engine, so there is no drag-to-place editor.
window.floorplan = (function () {
    let panCleanup = null;

    function readPan(el) {
        const m = el.style.transform.match(/translate\(([^,]+)px,\s*([^)]+)px\)/);
        return m ? [parseFloat(m[1]), parseFloat(m[2])] : [0, 0];
    }

    function applyPan(el, tx, ty) {
        el.style.transform = el.style.transform.replace(
            /translate\([^)]*\)/,
            `translate(${tx.toFixed(1)}px,${ty.toFixed(1)}px)`
        );
    }

    return {
        initPan(ref, wrapperEl, stage) {
            if (wrapperEl._panReady) return;
            wrapperEl._panReady = true;

            if (panCleanup) { panCleanup(); panCleanup = null; }

            let panning = false;
            let sx, sy, spx, spy;

            function onDown(e) {
                if (e.button !== 0) return;
                if (e.target.closest('.fp-room,.fp-zoom-controls,button,select,input')) return;
                panning = true;
                sx = e.clientX; sy = e.clientY;
                [spx, spy] = readPan(stage);
                wrapperEl.style.cursor = 'grabbing';
                e.preventDefault();
            }
            function onMove(e) {
                if (!panning) return;
                applyPan(stage, spx + e.clientX - sx, spy + e.clientY - sy);
            }
            function onUp() {
                if (!panning) return;
                panning = false;
                wrapperEl.style.cursor = '';
                const [tx, ty] = readPan(stage);
                ref.invokeMethodAsync('SetPan', tx, ty);
            }

            wrapperEl.addEventListener('mousedown', onDown);
            window.addEventListener('mousemove', onMove);
            window.addEventListener('mouseup', onUp);

            panCleanup = () => {
                wrapperEl.removeEventListener('mousedown', onDown);
                window.removeEventListener('mousemove', onMove);
                window.removeEventListener('mouseup', onUp);
            };
        }
    };
})();
